const CLOSE_AUTH = 'Basic YXBpXzJKd0JqaHMwYmZCUmJ5d3dHeXA0blUuMWlWV0NZVUUyRzE3NWh6NjJmNEJMRzo=';
const SB = $env.SUPABASE_LEADS_URL;
const KEY = $env.SUPABASE_LEADS_KEY;
const h = { apikey: KEY, Authorization: 'Bearer ' + KEY };

// 1. EG stattgefunden type
const types = await this.helpers.httpRequest({
  url: SB + '/rest/v1/custom_activity_types?close_type_id=eq.actitype_0Pow7dFbqAOrFjLsCT068D&select=id',
  headers: h
});
if (!types?.length) return [{ json: { _noWork: true } }];

// 2. Recent EG activities (90 days, limit 20)
const cutoff = new Date(Date.now() - 90 * 24 * 60 * 60 * 1000).toISOString();
const acts = await this.helpers.httpRequest({
  url: SB + '/rest/v1/custom_activities?type_id=eq.' + types[0].id + '&close_created_at=gte.' + cutoff + '&select=close_activity_id,close_lead_id,user_id,close_created_at&order=close_created_at.desc&limit=20',
  headers: h
});
if (!acts?.length) return [{ json: { _noWork: true } }];

// 3. Lead UUID mapping
const lids = [...new Set(acts.map(a => a.close_lead_id).filter(Boolean))];
const leads = await this.helpers.httpRequest({
  url: SB + '/rest/v1/leads?close_lead_id=in.(' + lids.join(',') + ')&select=id,close_lead_id',
  headers: h
});
const lmap = {};
for (const l of leads) lmap[l.close_lead_id] = l.id;

// 4. Per activity: get calls from Close, check existing transcripts
const result = [];
for (const act of acts) {
  const lu = lmap[act.close_lead_id];
  if (!lu) continue;

  const d = new Date(act.close_created_at);
  const ds = new Date(d.getFullYear(), d.getMonth(), d.getDate()).toISOString();
  const de = new Date(d.getFullYear(), d.getMonth(), d.getDate() + 1).toISOString();

  try {
    const cr = await this.helpers.httpRequest({
      url: 'https://api.close.com/api/v1/activity/call/?lead_id=' + act.close_lead_id + '&date_created__gte=' + ds + '&date_created__lt=' + de + '&_limit=50',
      headers: { Authorization: CLOSE_AUTH, Accept: 'application/json' }
    });
    const recs = (cr.data || []).filter(c => c.recording_url);
    if (!recs.length) continue;

    // Supabase call UUIDs
    const cids = recs.map(c => c.id);
    const sc = await this.helpers.httpRequest({
      url: SB + '/rest/v1/calls?close_call_id=in.(' + cids.join(',') + ')&select=id,close_call_id',
      headers: h
    });
    const cm = {};
    for (const c of sc) cm[c.close_call_id] = c.id;

    // Existing transcripts
    const uuids = Object.values(cm);
    let done = new Set();
    if (uuids.length) {
      const ex = await this.helpers.httpRequest({
        url: SB + '/rest/v1/transcripts?source_type=eq.call&source_id=in.(' + uuids.join(',') + ')&select=source_id',
        headers: h
      });
      done = new Set((ex || []).map(t => t.source_id));
    }

    for (const call of recs) {
      const cu = cm[call.id];
      if (!cu || done.has(cu)) continue;
      result.push({ json: {
        closeCallId: call.id, callUuid: cu,
        leadId: act.close_lead_id, leadUuid: lu,
        ownerUuid: act.user_id,
        recordingUrl: call.recording_url,
        dateCreated: act.close_created_at
      }});
    }
    await new Promise(r => setTimeout(r, 300));
  } catch (e) { /* skip */ }
}

if (!result.length) return [{ json: { _noWork: true } }];
return result;

const item = $json;
const CLOSE_AUTH = 'Basic YXBpXzJKd0JqaHMwYmZCUmJ5d3dHeXA0blUuMWlWV0NZVUUyRzE3NWh6NjJmNEJMRzo=';

// 1. Resolve recording URL (Close 302 redirect)
let directUrl = item.recordingUrl;
try {
  const resp = await this.helpers.httpRequest({
    method: 'HEAD', url: item.recordingUrl,
    headers: { Authorization: CLOSE_AUTH },
    disableFollowRedirect: true, returnFullResponse: true, ignoreHttpStatusErrors: true
  });
  if (resp.headers?.location) directUrl = resp.headers.location;
} catch (e) {
  const loc = e?.response?.headers?.location || e?.cause?.response?.headers?.location;
  if (loc) directUrl = loc;
}

// 2. Download audio
let audioData;
try {
  audioData = await this.helpers.httpRequest({
    url: directUrl, encoding: 'arraybuffer', timeout: 120000
  });
} catch (e) {
  return [{ json: { _skipped: true, _reason: 'download_failed', closeCallId: item.closeCallId } }];
}

// 3. Whisper transcribe
let whisper;
try {
  const buf = Buffer.isBuffer(audioData) ? audioData : Buffer.from(audioData);
  whisper = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.openai.com/v1/audio/transcriptions',
    headers: { Authorization: 'Bearer ' + $env.OPENAI_API_KEY },
    formData: {
      model: 'whisper-1',
      language: 'de',
      file: { value: buf, options: { filename: 'audio.mp3', contentType: 'audio/mpeg' } }
    },
    timeout: 300000
  });
} catch (e) {
  return [{ json: { _skipped: true, _reason: 'transcribe_failed', closeCallId: item.closeCallId } }];
}

const text = whisper?.text || '';
if (!text) return [{ json: { _skipped: true, _reason: 'empty_transcript', closeCallId: item.closeCallId } }];

return [{ json: {
  source_type: 'call',
  source_id: item.callUuid,
  lead_id: item.leadUuid,
  content: text,
  recording_url: item.recordingUrl,
  call_type: 'erstgespraech',
  synced_at: new Date().toISOString(),
  _skipped: false
} }];

const items = $input.all();
const transcripts = items.map(i => i.json).filter(t => !t._skipped && t.source_type === 'call');
const skipped = items.filter(i => i.json._skipped).length;

return [{ json: { transcripts, count: transcripts.length, skipped } }];
